using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capabilities to the research agent.
/// Uses the DuckDuckGo Instant Answer API (no API key required).
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for information on a given query and returns relevant results. Use this to research topics, find facts, and gather information.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(query);

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync(cancellationToken);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new StringBuilder();
            results.AppendLine($"Search results for: \"{query}\"");
            results.AppendLine(new string('-', 40));

            // Abstract (main result)
            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.AppendLine($"\n[Source: {abstractSource}]");
                results.AppendLine(abstractText);
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics) && topics.ValueKind == JsonValueKind.Array)
            {
                int count = 0;
                foreach (var topic in topics.EnumerateArray())
                {
                    if (count >= 5) break;

                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.AppendLine($"\n• {text}");
                        count++;
                    }
                }
            }

            // Answer (direct answer if available)
            var answer = root.GetProperty("Answer").GetString();
            if (!string.IsNullOrWhiteSpace(answer))
            {
                results.AppendLine($"\nDirect answer: {answer}");
            }

            var result = results.ToString();
            return string.IsNullOrWhiteSpace(abstractText) && string.IsNullOrWhiteSpace(answer)
                ? $"No detailed results found for \"{query}\". Try rephrasing or breaking the query into smaller parts."
                : result;
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}. Please try again.";
        }
    }

    public AIFunction AsAIFunction()
    {
        return AIFunctionFactory.Create(SearchWebAsync, name: "search_web", options: new AIFunctionFactoryOptions
        {
            Name = "search_web",
            Description = "Searches the web for information on a given query and returns relevant results.",
        });
    }
}

using System.Collections.Concurrent;
using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities to the research agent.
/// Stores notes in memory and allows retrieval for summarization.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly ConcurrentBag<ResearchNote> _notes = [];

    public IReadOnlyCollection<ResearchNote> Notes => [.. _notes];

    [Description("Saves a research note with a title and content. Use this to record key findings during research.")]
    public string TakeNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(title);
        ArgumentException.ThrowIfNullOrWhiteSpace(content);

        var note = new ResearchNote(title, content, DateTime.UtcNow);
        _notes.Add(note);

        return $"Note saved: \"{title}\" ({content.Length} chars). Total notes: {_notes.Count}.";
    }

    [Description("Retrieves all saved research notes. Use this to review collected information before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.IsEmpty)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===\n");

        int index = 1;
        foreach (var note in _notes.Reverse())
        {
            sb.AppendLine($"--- Note {index}: {note.Title} ---");
            sb.AppendLine($"Recorded: {note.Timestamp:u}");
            sb.AppendLine(note.Content);
            sb.AppendLine();
            index++;
        }

        return sb.ToString();
    }

    public IList<AIFunction> AsAIFunctions()
    {
        return
        [
            AIFunctionFactory.Create(TakeNote, name: "take_note", options: new AIFunctionFactoryOptions
            {
                Name = "take_note",
                Description = "Saves a research note with a title and content. Use this to record key findings.",
            }),
            AIFunctionFactory.Create(GetAllNotes, name: "get_all_notes", options: new AIFunctionFactoryOptions
            {
                Name = "get_all_notes",
                Description = "Retrieves all saved research notes for review before summarization.",
            }),
        ];
    }
}

public sealed record ResearchNote(string Title, string Content, DateTime Timestamp);

