using System.Collections.Concurrent;
using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities to the research agent.
/// Stores notes in memory and allows retrieval for summarization.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly ConcurrentBag<ResearchNote> _notes = [];

    public IReadOnlyCollection<ResearchNote> Notes => [.. _notes];

    [Description("Saves a research note with a title and content. Use this to record key findings during research.")]
    public string TakeNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(title);
        ArgumentException.ThrowIfNullOrWhiteSpace(content);

        var note = new ResearchNote(title, content, DateTime.UtcNow);
        _notes.Add(note);

        return $"Note saved: \"{title}\" ({content.Length} chars). Total notes: {_notes.Count}.";
    }

    [Description("Retrieves all saved research notes. Use this to review collected information before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.IsEmpty)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===\n");

        int index = 1;
        foreach (var note in _notes.Reverse())
        {
            sb.AppendLine($"--- Note {index}: {note.Title} ---");
            sb.AppendLine($"Recorded: {note.Timestamp:u}");
            sb.AppendLine(note.Content);
            sb.AppendLine();
            index++;
        }

        return sb.ToString();
    }

    public IList<AIFunction> AsAIFunctions()
    {
        return
        [
            AIFunctionFactory.Create(TakeNote, name: "take_note", options: new AIFunctionFactoryOptions
            {
                Name = "take_note",
                Description = "Saves a research note with a title and content. Use this to record key findings.",
            }),
            AIFunctionFactory.Create(GetAllNotes, name: "get_all_notes", options: new AIFunctionFactoryOptions
            {
                Name = "get_all_notes",
                Description = "Retrieves all saved research notes for review before summarization.",
            }),
        ];
    }
}

public sealed record ResearchNote(string Title, string Content, DateTime Timestamp);

