using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run the research agent.");

// --- Configure the LLM provider through MEAI abstractions ---
const string modelId = "gpt-4o-mini-2024-07-18";
IChatClient chatClient = new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient();

// --- Set up tools ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var webSearch = new WebSearchTool(httpClient);
var noteTaking = new NoteTakingTool();

var tools = new List<AITool>();
tools.Add(webSearch.AsAIFunction());
tools.AddRange(noteTaking.AsAIFunctions());

// --- Create the research agent using Microsoft Agent Framework ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = tools,
        },
    });

// --- Get the research topic ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent               ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
    Console.WriteLine($"Topic: {topic}");
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim()
        ?? throw new InvalidOperationException("No topic provided.");
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("Error: topic cannot be empty.");
    return 1;
}

Console.WriteLine($"\nResearching: \"{topic}\"...\n");

// --- Run the agent ---
var session = await agent.CreateSessionAsync();

var prompt = $"""
    You are a research assistant. Your task is to thoroughly research the following topic
    and produce a well-organized summary.

    Topic: {topic}

    Instructions:
    1. Use the search_web tool to search for information about this topic.
       Perform at least 2-3 searches with different queries to get comprehensive coverage.
    2. After each search, use the take_note tool to save the most important findings.
    3. Once you have gathered enough information, use get_all_notes to review everything.
    4. Finally, write a comprehensive summary that synthesizes all your research.

    Structure your final summary with:
    - A brief overview
    - Key findings (as bullet points)
    - Important details or context
    - A conclusion

    Begin your research now.
    """;

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(prompt, session, runOptions);

// --- Display results ---
Console.WriteLine("════════════════════════════════════════");
Console.WriteLine("              RESEARCH RESULTS          ");
Console.WriteLine("════════════════════════════════════════");
Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();

// --- Show collected notes ---
var notes = noteTaking.Notes;
if (notes.Count > 0)
{
    Console.WriteLine($"[Agent collected {notes.Count} research note(s) during this session]");
}

var usage = response.Usage;
if (usage is not null)
{
    Console.WriteLine($"[Tokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}, total: {usage.TotalTokenCount}]");
}

return 0;

