18.     [Description("Saves a research note with a title and content. Use this to record key findings during research.")]
19.     public string TakeNote(
20.         [Description("A short descriptive title for the note")] string title,
21.         [Description("The detailed content of the note")] string content)
22.     {
23.         ArgumentException.ThrowIfNullOrWhiteSpace(title);
24.         ArgumentException.ThrowIfNullOrWhiteSpace(content);
25. 
26.         var note = new ResearchNote(title, content, DateTime.UtcNow);
27.         _notes.Add(note);
28. 
29.         return $"Note saved: \"{title}\" ({content.Length} chars). Total notes: {_notes.Count}.";
30.     }
